function [y,n] = seqmult(x1,n1,x2,n2)
n = min(min(n1),min(n2)):max(max(n1),max(n2)); 
y1 = zeros(1,length(n));  
y2 = y1; 
y1(find((n>=min(n1))&(n<=max(n1))))=x1; 
y2(find((n>=min(n2))&(n<=max(n2))))=x2; 
y = y1.*y2;                                    
% 等长的序列y1和y2相乘
% y1和y2都具有最终的相同的长度n
% 确定n的范围
% 将x1的值放入y1中，位置保持好
% 将x2的值放入y2中，位置保持好
